package com.hospital.management.controller.appointment;import com.hospital.management.model.Appointment;import com.hospital.management.service.*;import com.hospital.management.service.impl.AppointmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/appointments/view")public class AppointmentViewServlet extends HttpServlet {private final AppointmentService service;public AppointmentViewServlet(){this(new AppointmentServiceImpl());}public AppointmentViewServlet(AppointmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AppointmentRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Appointment a=service.getAppointment(id,AppointmentRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}q.setAttribute("appointment",a);q.getRequestDispatcher("/WEB-INF/views/appointments/view.jsp").forward(q,r);}}
